import 'package:baseball_detector_flutter/data/repositories/repository.dart';
import 'package:baseball_detector_flutter/data/result.dart';

class APIServerRepository extends Repository {
  static final _fc =
      failureCodeBuilder.category('DASR'); // Data-ApiServerRepository
  static final _logger = FimberLog('APIServerRepository');
  static const _searchCountLimit = 10000;

  final ProfileStorage profileStorage;
  late final APIServerClient _client;

  APIServerRepository({
    required this.profileStorage,
    required Locale locale,
    required String? appVersion,
  }) {
    _client = APIServerClient(
      locale: locale,
      appVersion: appVersion,
    );
  }

  ResourceData _reprocessResource(
    ResourceData resource,
    String teamId,
    String sessionId,
    String? userId,
  ) {
    return resource.copyWith(
      teamId: teamId,
      sessionId: sessionId,
      userId: userId ?? resource.userId,
    );
  }

  ResourceData _reprocessResourceWithBallInfo(
    ResourceData resource,
    String teamId,
    String sessionId,
    String? userId,
  ) {
    final ballInfoList = resource.ballInfoList!.toList()
      ..retainWhere((ballInfo) =>
          (ballInfo.ball.isPitched ?? false) || (ballInfo.ball.isHit ?? false));

    return _reprocessResource(
      resource.copyWith(ballInfoList: ballInfoList),
      teamId,
      sessionId,
      userId,
    );
  }

  @override
  Future<Result<Failure, SessionSearchResponse>> getSessions({
    required int page,
    required int pageSize,
    required bool isTeamCrossing,
    String? location,
    String? playerId,
    DateTime? startDate,
    DateTime? endDate,
  }) async {
    final methodFc = _fc.category('GSS');

    final userId = profileStorage.getUserId();
    final userTeamId = profileStorage.getTeamId();
    if (userId == null || userTeamId == null) {
      // NOTE: This happens by logging out and logging back in again
      return Left(Failure.undefined(code: methodFc.position('001')));
    }

    // Use the isTeamCrossing parameter passed from the caller
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$userTeamId/sessions/search',
      data: SessionSearchRequest(
        page: page,
        pageSize: pageSize,
        userId: isTeamCrossing ? null : userId,
        playerId: playerId,
        location: location,
        dateFrom: startDate?.toUtc(),
        dateTo: endDate?.toUtc(),
        orderBy: SessionSearchRequestOrderBy.createdAt,
        isOrderDesc: true,
      ).toJson(),
      responseMapper: SessionSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, List<String>>> getSessionLocations({
    required bool isTeamCrossing,
  }) async {
    final methodFc = _fc.category('GSL');

    final userId = profileStorage.getUserId();
    final userTeamId = profileStorage.getTeamId();
    if (userId == null || userTeamId == null) {
      // NOTE: This happens by logging out and logging back in again
      return Left(Failure.undefined(code: methodFc.position('001')));
    }

    final response = await _client.request(
      method: 'GET',
      path: '/teams/$userTeamId/sessions/locations',
      queryParameters: {
        if (!isTeamCrossing) 'userId': userId,
      },
      responseMapper: SessionLocationsResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.locations);
  }

  @override
  Future<Result<Failure, Session>> getSessionDetail({
    required String teamId,
    required String sessionId,
  }) async {
    final response = await _client.request(
      method: 'GET',
      path: '/teams/$teamId/sessions/$sessionId',
      responseMapper: SessionDetailResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.session);
  }

  @override
  Future<Result<Failure, PlayerSearchResponse>> getPlayers({
    required int page,
    required int pageSize,
    required bool isTeamCrossing,
  }) async {
    final userId = profileStorage.getUserId();
    final userTeamId = profileStorage.getTeamId();
    // Use the isTeamCrossing parameter passed from the caller
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$userTeamId/players/search',
      data: PlayerSearchRequest(
        page: page,
        pageSize: pageSize,
        userId: isTeamCrossing ? null : userId,
        orderBy: PlayerSearchRequestOrderBy.name,
      ).toJson(),
      responseMapper: PlayerSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, ResourceSearchResponse>> getResources({
    required String teamId,
    required String sessionId,
    required int page,
    required int pageSize,
    required bool isTeamCrossing,
  }) async {
    final userId = profileStorage.getUserId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/sessions/$sessionId/resources/search',
      data: ResourceSearchRequest(
        userId: isTeamCrossing ? null : userId,
        page: page,
        pageSize: pageSize,
        orderBy: ResourceSearchRequestOrderBy.createdAt,
        isOrderDesc: true,
      ).toJson(),
      responseMapper: ResourceSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }

    return Right(
      response.right.copyWith(
        resources: response.right.resources
            .map(
              (resource) => _reprocessResourceWithBallInfo(
                resource,
                teamId,
                sessionId,
                resource.session?.userId,
              ),
            )
            .toList(),
      ),
    );
  }

  @override
  Future<Result<Failure, ResourceData>> getResourceDetail({
    required String teamId,
    required String sessionId,
    required String resourceId,
  }) async {
    final response = await _client.request(
      method: 'GET',
      path: '/teams/$teamId/sessions/$sessionId/resources/$resourceId',
      responseMapper: ResourceDetailResponse.fromJson,
    );

    if (response.hasLeft) {
      return Left(response.left);
    }

    final resourceData = _reprocessResourceWithBallInfo(
      response.right.resource,
      teamId,
      sessionId,
      response.right.resource.session?.userId,
    );

    return Right(resourceData);
  }

  @override
  Future<Result<Failure, Ball>> getBall({
    required String teamId,
    required String sessionId,
    required String resourceId,
    required int ballId,
  }) async {
    final response = await _client.request(
      method: 'GET',
      path:
          '/teams/$teamId/sessions/$sessionId/resources/$resourceId/balls/$ballId',
      responseMapper: BallResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.ball);
  }

  @override
  Future<Result<Failure, List<PitchType>>> getPitchTypes() async {
    final response = await _client.request(
      method: 'GET',
      path: '/pitch-types',
      responseMapper: PitchTypeResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.pitchTypes);
  }

  @override
  Future<Result<Failure, UserInfo>> getUserInfo() async {
    final response = await _client.request(
      method: 'GET',
      path: '/users/me',
      responseMapper: UserDetailResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.user);
  }

  @override
  Future<Result<Failure, UserAccessibleContents>>
      getAccessibleContents() async {
    final response = await _client.request(
      method: 'GET',
      path: '/users/me',
      responseMapper: UserDetailResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.user.accessibleContents);
  }

  @override
  Future<Result<Failure, UserSearchResponse>> getTeamMembers({
    required int page,
    required int pageSize,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/users/search',
      data: UserSearchRequest(
        page: page,
        pageSize: pageSize,
        orderBy: UserSearchRequestOrderBy.name,
      ).toJson(),
      responseMapper: UserSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, List<Team>>> getTeams() async {
    final response = await _client.request(
      method: 'POST',
      path: '/teams/search',
      data: const TeamSearchRequest(
        pageSize: _searchCountLimit,
        orderBy: TeamSearchRequestOrderBy.name,
      ).toJson(),
      responseMapper: TeamSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.teams);
  }

  @override
  Future<Result<Failure, List<Notification>>> getNotifications({
    String? keyword,
    int page = 0,
    int? pageSize = 10,
  }) async {
    final response = await _client.request(
      method: 'POST',
      path: '/users/me/notifications/search',
      data: NotificationSearchRequest(
        keyword: keyword,
        page: page,
        pageSize: pageSize ?? _searchCountLimit,
        orderBy: NotificationSearchRequestOrderBy.createdAt,
        isOrderDesc: true,
      ).toJson(),
      responseMapper: NotificationSearchResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.notifications);
  }

  @override
  Future<Result<Failure, void>> setNotificationRead({
    required String notificationId,
  }) async {
    final response = await _client.request(
      method: 'PUT',
      path: '/users/me/notifications/$notificationId',
      data: SetNotificationAsReadRequest(
        isRead: true,
      ).toJson(),
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(null);
  }

  @override
  Future<Result<Failure, SessionAddResponse>> addSession({
    required String playerId,
    required String location,
    required String note,
    required String title,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/sessions',
      data: SessionAddRequest(
        playerId: playerId,
        title: title,
        location: location,
        note: note,
      ).toJson(),
      responseMapper: SessionAddResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, PlayerCreateResponse>> addPlayer({
    required String playerName,
    required String note,
    required Handedness pitchingHand,
    required Handedness hittingHand,
    DateTime? birthday,
  }) async {
    final teamId = profileStorage.getTeamId();
    final userId = profileStorage.getUserId()!;
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/players',
      data: PlayerCreateRequest(
        name: playerName,
        note: note,
        userId: userId,
        pitchingHand: pitchingHand,
        hittingHand: hittingHand,
        birthday: birthday,
      ).toJson(),
      responseMapper: PlayerCreateResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, SessionDeleteResponse>> deleteSession({
    required String sessionId,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'DELETE',
      path: '/teams/$teamId/sessions/$sessionId',
      responseMapper: SessionDeleteResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
