void main() {
  group('Testing PlayerSearchRequest', () {
    const userId = '22222222-0000-0000-0000-000000000000';
    const keyword = 'keyword';
    const isKeywordUsedAsFuzzySearch = false;
    const page = 0;
    const pageSize = 20;
    const orderBy = PlayerSearchRequestOrderBy.id;
    const isOrderDesc = false;

    test('toJson1', () {
      const req = PlayerSearchRequest(
        userId: userId,
        keyword: keyword,
        isKeywordUsedAsFuzzySearch: isKeywordUsedAsFuzzySearch,
        page: page,
        pageSize: pageSize,
        orderBy: orderBy,
        isOrderDesc: isOrderDesc,
      );

      final reqJson = req.toJson();

      expect(reqJson.length, 7);

      expect(reqJson.containsKey('userId'), isTrue);
      expect(reqJson.containsKey('keyword'), isTrue);
      expect(reqJson.containsKey('isKeywordUsedAsFuzzySearch'), isTrue);
      expect(reqJson.containsKey('page'), isTrue);
      expect(reqJson.containsKey('pageSize'), isTrue);
      expect(reqJson.containsKey('orderBy'), isTrue);
      expect(reqJson.containsKey('isOrderDesc'), isTrue);

      expect(reqJson['userId'], userId);
      expect(reqJson['keyword'], keyword);
      expect(reqJson['isKeywordUsedAsFuzzySearch'], isKeywordUsedAsFuzzySearch);
      expect(reqJson['page'], page);
      expect(reqJson['pageSize'], pageSize);
      expect(reqJson['orderBy'], orderBy.name);
      expect(reqJson['isOrderDesc'], isOrderDesc);
    });
  });
}

