    const page = 0;
    const pageSize = 20;
    const orderBy = SessionSearchRequestOrderBy.id;
    const isOrderDesc = false;

    test('toJson1', () {
      final req = SessionSearchRequest(
        keyword: keyword,
        userId: userId,
        location: location,
        playerId: playerId,
        dateFrom: dateFrom,
        dateTo: dateTo,
        page: page,
        pageSize: pageSize,
        orderBy: orderBy,
        isOrderDesc: isOrderDesc,
      );

      final reqJson = req.toJson();

      expect(reqJson.length, 10);

      expect(reqJson.containsKey('keyword'), isTrue);
      expect(reqJson.containsKey('userId'), isTrue);
      expect(reqJson.containsKey('location'), isTrue);
      expect(reqJson.containsKey('playerId'), isTrue);
      expect(reqJson.containsKey('dateFrom'), isTrue);
      expect(reqJson.containsKey('dateTo'), isTrue);
      expect(reqJson.containsKey('page'), isTrue);
      expect(reqJson.containsKey('pageSize'), isTrue);
      expect(reqJson.containsKey('orderBy'), isTrue);
      expect(reqJson.containsKey('isOrderDesc'), isTrue);

      expect(reqJson['keyword'], keyword);
      expect(reqJson['userId'], userId);
      expect(reqJson['location'], location);
      expect(reqJson['playerId'], playerId);
      expect(reqJson['dateFrom'], dateFrom.toIso8601String());
      expect(reqJson['dateTo'], dateTo.toIso8601String());
      expect(reqJson['page'], page);
      expect(reqJson['pageSize'], pageSize);
      expect(reqJson['orderBy'], orderBy.name);
      expect(reqJson['isOrderDesc'], isOrderDesc);
    });
  });
}

