// Flutter imports:

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:visibility_detector/visibility_detector.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/utils/paging_notifier_mixin.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/hooks/use_access_denied_navigation.dart';

class PagingHelper<N extends AsyncNotifier<PagingData<I>>, I>
    extends HookConsumerWidget {
  const PagingHelper({
    required this.provider,
    required this.contentBuilder,
    this.pageSize,
    super.key,
  });

  final AsyncNotifierProvider<N, PagingData<I>> provider;
  final Widget Function(PagingData<I> data, Widget? endItemView) contentBuilder;
  final int? pageSize;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final handleAccessDenied = useAccessDeniedNavigation();
    // Show error snackbar when error occurs
    ref.listen<AsyncValue<PagingData<I>>>(provider, (previous, next) {
      if (!next.isLoading && next.hasError) {
        final error = next.error;
        if (error is Failure) {
          context.showErrorSnackBar(error.translate(context.l10n));
        } else {
          context.showErrorSnackBar(error.toString());
        }
      }
    });

    final asyncValue = ref.watch(provider);
    final notifier = ref.read(provider.notifier);
    return asyncValue.when(
      data: (data) {
        return RefreshIndicator(
          onRefresh: () async {
            if (!context.mounted) return;

            // Refresh user's accessible contents to get latest role permissions
            await ref
                .read(userAccessibleContentsControllerProvider.notifier)
                .refresh();

            if (!context.mounted) return;

            (notifier as PagePagingNotifierMixin<I>).forceRefresh();
            if (context.mounted) {
              await ref.read(provider.future);
            }
          },
          child: contentBuilder(
            data,
            data.hasMore && !asyncValue.hasError
                ? EndItemView(
                    visibilityKey: Key('EndItem_${data.items.length}'),
                    onScrollEnd: () async {
                      final notifier = ref.read(provider.notifier)
                          as PagePagingNotifierMixin<I>;
                      await notifier.loadNext(pageSize: pageSize);
                    },
                  )
                : null,
          ),
        );
      },
      loading: () => const Center(child: CustomLoadingIndicator()),
      error: (error, stackTrace) {
        if (error is ForbiddenFailure) {
          ref.read(userAccessibleContentsControllerProvider.notifier).refresh();
          handleAccessDenied();
          return const SizedBox.shrink();
        }
        return Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              IconButton(
                onPressed: () {
                  (notifier as PagePagingNotifierMixin<I>).forceRefresh();
                },
                icon: const Icon(Icons.refresh),
              ),
              Text(context.l10n.get_data_failed),
              const Gap(8),
              Text(
                (error is Failure)
                    ? error.translate(context.l10n)
                    : error.toString(),
                textAlign: TextAlign.center,
              ),
            ],
          ),
        );
      },
    );
  }
}

class AutoDisposePagingHelper<N extends AutoDisposeAsyncNotifier<PagingData<I>>,
    I> extends HookConsumerWidget {
  const AutoDisposePagingHelper({
    required this.provider,
    required this.contentBuilder,
    this.pageSize,
    super.key,
  });

  final AutoDisposeAsyncNotifierProvider<N, PagingData<I>> provider;
  final Widget Function(PagingData<I> data, Widget? endItemView) contentBuilder;
  final int? pageSize;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final handleAccessDenied = useAccessDeniedNavigation();
    // Show error snackbar when error occurs
    ref.listen<AsyncValue<PagingData<I>>>(provider, (previous, next) {
      if (!next.isLoading && next.hasError) {
        final error = next.error;
        if (error is Failure) {
          context.showErrorSnackBar(error.translate(context.l10n));
        } else {
          context.showErrorSnackBar(error.toString());
        }
      }
    });

    final asyncValue = ref.watch(provider);
    final notifier = ref.read(provider.notifier);
    return asyncValue.when(
      data: (data) {
        return RefreshIndicator(
          onRefresh: () async {
            if (!context.mounted) return;

            // Refresh user's accessible contents to get latest role permissions
            await ref
                .read(userAccessibleContentsControllerProvider.notifier)
                .refresh();

            if (!context.mounted) return;

            (notifier as AutoDisposePagePagingNotifierMixin<I>).forceRefresh();
            if (context.mounted) {
              await ref.read(provider.future);
            }
          },
          child: contentBuilder(
            data,
            data.hasMore && !asyncValue.hasError
                ? EndItemView(
                    visibilityKey: Key('EndItem_${data.items.length}'),
                    onScrollEnd: () async {
                      final notifier = ref.read(provider.notifier)
                          as AutoDisposePagePagingNotifierMixin<I>;
                      await notifier.loadNext(pageSize: pageSize);
                    },
                  )
                : null,
          ),
        );
      },
      loading: () => const Center(child: CustomLoadingIndicator()),
      error: (error, stackTrace) {
        if (error is ForbiddenFailure) {
          ref.read(userAccessibleContentsControllerProvider.notifier).refresh();
          handleAccessDenied();
          return const SizedBox.shrink();
        }
        return Center(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              IconButton(
                onPressed: () {
                  (notifier as AutoDisposePagePagingNotifierMixin<I>)
                      .forceRefresh();
                },
                icon: const Icon(Icons.refresh),
              ),
              Text(context.l10n.get_data_failed),
              const SizedBox(height: 8),
              Text(
                (error is Failure)
                    ? error.translate(context.l10n)
                    : error.toString(),
                textAlign: TextAlign.center,
              ),
            ],
          ),
        );
      },
    );
  }
}

class EndItemView extends StatelessWidget {
  const EndItemView({
    required this.onScrollEnd,
    required this.visibilityKey,
    super.key,
  });

  final VoidCallback onScrollEnd;
  final Key visibilityKey;

  @override
  Widget build(BuildContext context) {
    return VisibilityDetector(
      key: visibilityKey,
      onVisibilityChanged: (info) {
        if (info.visibleFraction > 0.1) {
          onScrollEnd();
        }
      },
      child: const Center(
        child: Padding(
          padding: EdgeInsets.all(16),
          child: CircularProgressIndicator(),
        ),
      ),
    );
  }
}

